const item = $json;
const attachments = item.fields?.attachment || [];

// Функция для расшифровки URL-encoded строки
function decodeFileName(name) {
  if (!name) return null;
  try {
    // Заменяем + на пробелы и декодируем URL
    return decodeURIComponent(name.replace(/\+/g, ' '));
  } catch (e) {
    return name;
  }
}

// Функция для определения типа по названию
function getType(name) {
  if (!name) return 'unknown';
  const decoded = decodeFileName(name).toLowerCase();
  if (decoded.includes('креатив') || decoded.includes('creative')) return 'creative';
  if (decoded.includes('дизайн') || decoded.includes('design')) return 'design';
  return 'unknown';
}

// Определяем дизайн и креатив по названию, а не по порядку
let design = null;
let creative = null;

for (const att of attachments) {
  const type = getType(att.name || att.filename || '');
  if (type === 'design' && !design) {
    design = att;
  } else if (type === 'creative' && !creative) {
    creative = att;
  }
}

// Если не нашли по названию — берём по порядку
if (!design) design = attachments[0] || null;
if (!creative) creative = attachments[1] || null;

const designContent = design ? design.content || null : null;
const designId = design ? design.id || null : null;
const designName = design ? decodeFileName(design.name || design.filename) : null;

const creativeContent = creative ? creative.content || null : null;
const creativeId = creative ? creative.id || null : null;
const creativeName = creative ? decodeFileName(creative.name || creative.filename) : null;

return {
  json: {
    ...item,
    designContent,
    designId,
    designName,
    creativeContent,
    creativeId,
    creativeName,
  },
};

