}

const data = JSON.parse(resultJson);
const url = data.resultUrls?.[0] || '';

// Сохраняем index из Loop Over Items
const index = $('Loop Over Items').item.json.index;
const name = $('Loop Over Items').item.json.name;

return [{ 
  json: { 
    extractedUrl: url,
    index: index,
    name: name
  } 
}];

const item = $input.first();

// Используем $runIndex - это номер текущей итерации Loop Over Items
const index = $runIndex ?? 0;

// Настройки сетки
const columns = 5;
const baseX = 100;
const baseY = 3500;
const spacingX = 50;
const spacingY = 50;

const width = $('Upload file media4').item.json.width;
const height = $('Upload file media4').item.json.height;

const col = index % columns;
const row = Math.floor(index / columns);

const x = baseX + col * (width + spacingX);
const y = baseY + row * (height + spacingY);

return [{
  json: {
    ...item.json,
    posX: x,
    posY: y,
    width: width,
    height: height,
    index: index  // для отладки
  }
}];

// Code node для n8n (Run Once for Items)
const inputText = $json.body?.comment || $json.output || $json.text || '';

let screenNumber = 0;

// Вариант 1: "экран 3" или "Экран 3"
const match1 = inputText.match(/экран\s*(\d+)/i);

// Вариант 2: "3 экран" или "3-й экран" или "3й экран"
const match2 = inputText.match(/(\d+)\s*-?й?\s*экран/i);

if (match1) {
  screenNumber = parseInt(match1[1]);
} else if (match2) {
  screenNumber = parseInt(match2[1]);
}

// Убираем все варианты номера экрана из текста
const screenText = inputText
  .replace(/экран\s*\d+\s*[-–—]?\s*/gi, '')
  .replace(/\d+\s*-?й?\s*экран\s*[-–—]?\s*/gi, '')
  .trim();

return {
  json: {
    screen_number: screenNumber ? `экран ${screenNumber}` : 'экран 0',
    screen_text: screenText,
    full_text: inputText
  }
};

const fileData = $input.first().json;
const screenNumber = $('Code in JavaScript10').item.json.screen_number;

const searchName = screenNumber.toString().toLowerCase().trim();
const searchNum = searchName.match(/\d+/)?.[0] || '';

let foundImage = null;
const allImages = [];

// Ищем по ВСЕМ страницам
const pages = fileData.data?.pages || [];
const pagesIndex = fileData.data?.pagesIndex || {};

for (const pageId of pages) {
  const pageData = pagesIndex[pageId];
  if (!pageData?.objects) continue;

  // Ищем по всем объектам на странице
  for (const [id, obj] of Object.entries(pageData.objects)) {

    // Проверяем сам объект
    if (obj.type === 'image' && obj.name) {
      allImages.push(obj.name);

      const name = obj.name.toLowerCase().trim();
      const nameNum = name.match(/\d+/)?.[0] || '';

      if (nameNum === searchNum && name.includes('экран')) {
        foundImage = {
          id: id,
          name: obj.name,
          mediaId: obj.metadata?.id,
          width: obj.metadata?.width,
          height: obj.metadata?.height,
          mtype: obj.metadata?.mtype,
          x: obj.x,
          y: obj.y
        };
        break;
      }
    }

    // Проверяем вложенные объекты (если есть)
    if (obj.shapes) {
      for (const shapeId of obj.shapes) {
        const shape = pageData.objects[shapeId];
        if (shape?.type === 'image' && shape?.name) {
          allImages.push(shape.name);

          const name = shape.name.toLowerCase().trim();
          const nameNum = name.match(/\d+/)?.[0] || '';

          if (nameNum === searchNum && name.includes('экран')) {
            foundImage = {
              id: shapeId,
              name: shape.name,
              mediaId: shape.metadata?.id,
              width: shape.metadata?.width,
              height: shape.metadata?.height,
              mtype: shape.metadata?.mtype,
              x: shape.x,
              y: shape.y
            };
            break;
          }
        }
      }
    }
  }

  if (foundImage) break;
}

if (!foundImage || !foundImage.mediaId) {
  throw new Error(`Изображение "${searchName}" не найдено. Ищем номер: "${searchNum}". Найденные изображения: ${JSON.stringify(allImages)}`);
}

const downloadUrl = `https://penpot.itcomp.site/assets/by-file-media-id/${foundImage.mediaId}`;

return [{
  json: {
    ...foundImage,
    downloadUrl: downloadUrl,
    screen_number: screenNumber
  }
}];

const crypto = require('crypto');

for (const item of $input.all()) {
  item.json.uuid = crypto.randomUUID();
}

return $input.all();

const resultJson = $input.first().json.data?.resultJson;

if (!resultJson) {
  throw new Error('Нет data.resultJson');
}

const data = JSON.parse(resultJson);
const url = data.resultUrls?.[0] || '';

return [{ json: { extractedUrl: url } }];

const url = $input.first().json.urls; // входная ссылка

// URL формат: https://penpot.itcomp.site/#/workspace/PROJECT_ID/FILE_ID
const parts = url.split('/');
const fileId = parts[parts.length - 1].split('?')[0];
const projectId = parts[parts.length - 2];

return [
  {
    json: {
      fileId,
      projectId,
      originalUrl: url
    }
  }
