const name = $json.name;
const summary = $('Get an issue3').last().json.fields.summary;
const imageText = $('Analyze an image6').item.json.content.parts[0].text
  .replace(/"/g, '')
  .replace(/\n/g, ' ')
  .replace(/\r/g, '');

const prompt = `Сделай иконку мода, изучи как выглядит (${name}) в игре (определи по названию (${summary})) и дай мне превью для него, где это (${name}) на каком (${imageText}) фоне`;

return {
  json: {
    model: "nano-banana-pro",
    input: {
      prompt: prompt,
      output_format: "png"
    }
  }
};

const url = $input.first().json.urls;

const parts = url.split('/');
const fileId = parts[parts.length - 1].split('?')[0];
const projectId = parts[parts.length - 2];

return [{
  json: {
    fileId,
    projectId,
    originalUrl: url
  }
}];

const fileData = $input.first().json;
const fileId = fileData.id || '';

const allImages = [];

function findImages(obj, pageId = null) {
  if (!obj || typeof obj !== 'object') return;

  if (obj.id && obj.objects) {
    pageId = obj.id;
  }

  if (obj.type === 'image' && obj.name && obj.metadata?.id) {
    const nameMatch = obj.name.match(/\d+/);
    const nameNumber = nameMatch ? parseInt(nameMatch[0]) : 999;

    allImages.push({
      nameNumber: nameNumber,
      json: {
        id: obj.id || '',
        name: obj.name,
        mediaId: obj.metadata.id,
        width: obj.metadata.width,
        height: obj.metadata.height,
        mtype: obj.metadata.mtype,
        x: obj.x,
        y: obj.y,
        pageId: pageId,
        fileId: fileId,
        downloadUrl: `https://penpot.itcomp.site/assets/by-file-media-id/${obj.metadata.id}`
      }
    });
    return;
  }

  if (Array.isArray(obj)) {
    obj.forEach(item => findImages(item, pageId));
  } else {
    for (const [key, value] of Object.entries(obj)) {
      if (typeof value === 'object' && value !== null) {
        findImages(value, pageId);
      }
    }
  }
}

const defaultPageId = fileData.data?.pages?.[0] || '';
findImages(fileData, defaultPageId);

if (allImages.length === 0) {
